ValidationRule.errorConditionFormula:
AND(
  NOT(ISBLANK(CAZ_Fecha_Reprogramacion__c)),
  NOT(ISBLANK(CAZ_Numero_Orden__c)),
  NOT(ISBLANK(CAZ_Numero_Orden__r.EffectiveDate)),

  OR(
    /* 1) No permitir fechas pasadas */
    CAZ_Fecha_Reprogramacion__c < TODAY(),

    /* 2) No permitir reprogramar antes o el mismo día de la fecha original */
    CAZ_Fecha_Reprogramacion__c <= CAZ_Numero_Orden__r.EffectiveDate,

    /* 3) No permitir exceder el último día del mes de la fecha original */
    CAZ_Fecha_Reprogramacion__c >
      (
        DATE(
          YEAR(CAZ_Numero_Orden__r.EffectiveDate),
          MONTH(CAZ_Numero_Orden__r.EffectiveDate) + 1,
          1
        ) - 1
      )
  )
)
